<?php
/**
 * Plugin Name: Tager Marketplace Pro Enhancements
 * Description: Customer accounts, vendor KYC, granular permissions, advanced products, multi-vendor order splitting, commissions, withdrawals, coupons, notifications and reports.
 * Version: 4.0.0
 */
if (!defined('ABSPATH')) exit;

class Tager_Pro_Enhancements {
    const V = '4.0.0';

    public static function init() {
        add_action('init', [__CLASS__, 'register'], 40);
        add_action('init', [__CLASS__, 'override_shortcodes'], 99);
        add_action('init', [__CLASS__, 'bootstrap'], 120);
        add_action('admin_menu', [__CLASS__, 'admin_menu'], 30);
        add_action('wp_enqueue_scripts', [__CLASS__, 'assets'], 30);

        foreach ([
            'profile_save','address_save','vendor_profile_save','vendor_product_save','vendor_withdrawal',
            'vendor_order_status','wishlist_toggle','coupon_create','coupon_delete','withdrawal_action','vendor_permission_save'
        ] as $a) add_action('admin_post_tager_'.$a, [__CLASS__, $a]);

        add_action('admin_post_nopriv_tager_wishlist_toggle', [__CLASS__, 'wishlist_toggle']);
        add_action('admin_post_nopriv_tager_pro_checkout', [__CLASS__, 'pro_checkout']);
        add_action('admin_post_tager_pro_checkout', [__CLASS__, 'pro_checkout']);
        add_action('admin_post_tager_vendor_kyc', [__CLASS__, 'vendor_kyc']);
        add_action('admin_post_nopriv_tager_vendor_kyc', [__CLASS__, 'vendor_kyc']);
        add_action('admin_post_tager_admin_vendor_review', [__CLASS__, 'admin_vendor_review']);
    }

    public static function register() {
        register_post_type('tager_suborder', [
            'labels'=>['name'=>'Vendor Suborders','singular_name'=>'Vendor Suborder'],
            'public'=>false,'show_ui'=>true,'supports'=>['title','author'],'menu_icon'=>'dashicons-list-view'
        ]);
        register_post_type('tager_withdrawal', [
            'labels'=>['name'=>'Vendor Withdrawals','singular_name'=>'Vendor Withdrawal'],
            'public'=>false,'show_ui'=>true,'supports'=>['title','author'],'menu_icon'=>'dashicons-money-alt'
        ]);
        register_post_type('tager_coupon', [
            'labels'=>['name'=>'Tager Coupons','singular_name'=>'Tager Coupon'],
            'public'=>false,'show_ui'=>false,'supports'=>['title','author']
        ]);
        register_taxonomy('tager_category','tager_product',[
            'labels'=>['name'=>'Product Categories','singular_name'=>'Product Category'],
            'public'=>true,'show_ui'=>true,'hierarchical'=>true,'rewrite'=>['slug'=>'category']
        ]);
    }

    public static function bootstrap() {
        if (get_option('tager_pro_bootstrap') === self::V) return;
        $pages = get_option('tager_pages', []);
        $extras = [
            'wishlist'=>['المفضلة','[tager_pro_wishlist]'],
            'vendor-store'=>['متجر المورد','[tager_pro_vendor_store]'],
            'order-tracking'=>['تتبع الطلب','[tager_pro_tracking]'],
        ];
        foreach ($extras as $slug=>$d) {
            $p=get_page_by_path($slug);
            $pages[$slug]=$p?$p->ID:wp_insert_post(['post_type'=>'page','post_status'=>'publish','post_name'=>$slug,'post_title'=>$d[0],'post_content'=>$d[1]]);
        }
        update_option('tager_pages',$pages);
        if (!get_option('tager_pro_settings')) update_option('tager_pro_settings',[
            'min_withdrawal'=>1000,'withdrawal_days'=>7,'vendor_docs_required'=>1,'allow_vendor_coupons'=>1,
            'allow_vendor_order_status'=>1,'allow_vendor_product_edit'=>1,'allow_vendor_product_delete'=>0,
            'require_email'=>1,'platform_name'=>'Tager','currency'=>'EGP'
        ]);
        update_option('tager_pro_bootstrap',self::V);
    }

    public static function override_shortcodes() {
        remove_shortcode('tager_customer_account'); add_shortcode('tager_customer_account',[__CLASS__,'customer_account']);
        remove_shortcode('tager_vendor_dashboard'); add_shortcode('tager_vendor_dashboard',[__CLASS__,'vendor_dashboard']);
        remove_shortcode('tager_cart'); add_shortcode('tager_cart',[__CLASS__,'cart']);
        remove_shortcode('tager_shop'); add_shortcode('tager_shop',[__CLASS__,'shop']);
        add_shortcode('tager_pro_wishlist',[__CLASS__,'wishlist']);
        add_shortcode('tager_pro_vendor_store',[__CLASS__,'vendor_store']);
        add_shortcode('tager_pro_tracking',[__CLASS__,'tracking']);
    }

    private static function lang(){return (isset($_GET['lang'])&&$_GET['lang']==='en')?'en':'ar';}
    private static function t($ar,$en){return self::lang()==='en'?$en:$ar;}
    private static function pages(){return get_option('tager_pages',[]);}
    private static function url($slug){$p=self::pages();return isset($p[$slug])?get_permalink($p[$slug]):home_url('/'.$slug.'/');}
    private static function pro(){return wp_parse_args(get_option('tager_pro_settings',[]),['min_withdrawal'=>1000,'withdrawal_days'=>7,'vendor_docs_required'=>1,'allow_vendor_coupons'=>1,'allow_vendor_order_status'=>1,'allow_vendor_product_edit'=>1,'allow_vendor_product_delete'=>0]);}
    private static function vendor_ok($uid=0){$uid=$uid?:get_current_user_id();$u=get_userdata($uid);return $u && (in_array('tager_vendor',$u->roles,true)||current_user_can('manage_options')) && get_user_meta($uid,'vendor_status',true)!=='suspended';}
    private static function money($v){return number_format((float)$v,2).' EGP';}
    private static function nonce_field($a){return wp_nonce_field($a,'_wpnonce',true,false);}
    private static function status_badge($s){$map=['pending'=>'warning','approved'=>'success','rejected'=>'danger','suspended'=>'danger','New'=>'info','Confirmed'=>'info','Processing'=>'warning','Shipped'=>'info','Completed'=>'success','Cancelled'=>'danger'];return '<span class="tag '.($map[$s]??'info').'">'.esc_html($s).'</span>';}

    public static function assets(){
        wp_add_inline_style('tager-style', self::css());
        wp_add_inline_script('tager-js', self::js(), 'after');
    }

    public static function shop(){
        $q=sanitize_text_field($_GET['q']??''); $cat=(int)($_GET['cat']??0); $sort=sanitize_key($_GET['sort']??'newest');
        $args=['post_type'=>'tager_product','post_status'=>'publish','posts_per_page'=>24,'s'=>$q,'meta_query'=>[['key'=>'approval_status','value'=>'approved']]];
        if($cat)$args['tax_query']=[['taxonomy'=>'tager_category','field'=>'term_id','terms'=>$cat]];
        if($sort==='price_low'){$args['meta_key']='retail_price';$args['orderby']='meta_value_num';$args['order']='ASC';}
        elseif($sort==='price_high'){$args['meta_key']='retail_price';$args['orderby']='meta_value_num';$args['order']='DESC';}
        $terms=get_terms(['taxonomy'=>'tager_category','hide_empty'=>false]);
        ob_start(); ?>
        <section class="page-hero"><h1><?php echo esc_html(self::t('المنتجات','Products'));?></h1><p><?php echo esc_html(self::t('قطاعي، جملة، وجملة الجملة في مكان واحد','Retail, wholesale and bulk wholesale in one place'));?></p></section>
        <form class="market-filters" method="get">
          <input name="q" value="<?php echo esc_attr($q);?>" placeholder="<?php echo esc_attr(self::t('ابحث باسم المنتج','Search products'));?>">
          <select name="cat"><option value="0"><?php echo esc_html(self::t('كل الأقسام','All categories'));?></option><?php foreach($terms as $tm)echo '<option value="'.$tm->term_id.'" '.selected($cat,$tm->term_id,false).'>'.esc_html($tm->name).'</option>';?></select>
          <select name="sort"><option value="newest"><?php echo esc_html(self::t('الأحدث','Newest'));?></option><option value="price_low" <?php selected($sort,'price_low');?>><?php echo esc_html(self::t('السعر: الأقل','Price: low to high'));?></option><option value="price_high" <?php selected($sort,'price_high');?>><?php echo esc_html(self::t('السعر: الأعلى','Price: high to low'));?></option></select>
          <button class="btn primary"><?php echo esc_html(self::t('بحث','Search'));?></button>
        </form>
        <?php echo self::grid($args); return ob_get_clean();
    }

    private static function grid($args){$q=new WP_Query($args);ob_start();echo '<div class="product-grid">';if(!$q->have_posts())echo '<div class="empty-state">'.esc_html(self::t('لا توجد منتجات مطابقة','No matching products')).'</div>';while($q->have_posts()){$q->the_post();$id=get_the_ID();$name=self::lang()==='en'?(get_post_meta($id,'name_en',true)?:get_the_title()):get_the_title();$vendor=(int)get_post_field('post_author',$id);$store=get_user_meta($vendor,'store_name',true)?:get_the_author_meta('display_name',$vendor);$r=(float)get_post_meta($id,'retail_price',true);$w=(float)get_post_meta($id,'wholesale_price',true);$b=(float)get_post_meta($id,'bulk_price',true);$wm=(int)get_post_meta($id,'wholesale_min',true);$bm=(int)get_post_meta($id,'bulk_min',true);$max=(int)(get_post_meta($id,'max_qty',true)?:9999);$stock=(int)get_post_meta($id,'stock',true);echo '<article class="product-card"><div class="product-image">'.(has_post_thumbnail()?get_the_post_thumbnail($id,'medium'):'<span>📦</span>').'<button class="wish-btn" onclick="tagerWish('.$id.')">♡</button></div><div class="product-body"><small class="vendor-name">'.esc_html($store).'</small><h3>'.esc_html($name).'</h3><div class="price"><b>'.self::money($r).'</b></div><div class="tiers"><span>'.esc_html(self::t('جملة','Wholesale')).': '.self::money($w).' / '.$wm.'+</span><span>'.esc_html(self::t('جملة الجملة','Bulk')).': '.self::money($b).' / '.$bm.'+</span></div><div class="stock-line">'.esc_html(self::t('المتاح','Stock')).': '.$stock.'</div><div class="qty-row"><input type="number" min="1" max="'.esc_attr(min($max,$stock)).'" value="1" id="qty-'.$id.'"><button class="btn primary" onclick="tagerAdd('.$id.',\''.esc_js($name).'\')">'.esc_html(self::t('أضف للسلة','Add to cart')).'</button></div></div></article>'; }wp_reset_postdata();echo '</div>';return ob_get_clean();}

    public static function customer_account(){
        if(!is_user_logged_in()) return '<section class="form-wrap"><h1>'.esc_html(self::t('تسجيل الدخول','Sign in')).'</h1>'.wp_login_form(['echo'=>false,'redirect'=>self::url('my-account')]).'<p><a href="'.esc_url(wp_lostpassword_url()).'">'.esc_html(self::t('نسيت كلمة المرور؟','Forgot password?')).'</a></p><a href="'.esc_url(self::url('customer-register')).'">'.esc_html(self::t('إنشاء حساب جديد','Create account')).'</a></section>';
        $u=wp_get_current_user(); if(in_array('tager_vendor',$u->roles,true)||in_array('tager_vendor_pending',$u->roles,true))return '<section class="form-wrap"><a class="btn primary" href="'.esc_url(self::url('vendor-dashboard')).'">'.esc_html(self::t('فتح لوحة المورد','Open vendor dashboard')).'</a></section>';
        $tab=sanitize_key($_GET['tab']??'overview'); ob_start(); ?>
        <section class="dash-shell"><aside class="dash-menu"><h3><?php echo esc_html($u->display_name);?></h3><?php foreach(['overview'=>['نظرة عامة','Overview'],'orders'=>['طلباتي','My orders'],'addresses'=>['العناوين','Addresses'],'wishlist'=>['المفضلة','Wishlist'],'profile'=>['الملف الشخصي','Profile']] as $k=>$v)echo '<a class="'.($tab===$k?'active':'').'" href="'.esc_url(add_query_arg('tab',$k,self::url('my-account'))).'">'.esc_html(self::t($v[0],$v[1])).'</a>';?><a href="<?php echo esc_url(wp_logout_url(home_url()));?>"><?php echo esc_html(self::t('تسجيل الخروج','Sign out'));?></a></aside><main class="dash-content">
        <?php if($tab==='orders')self::customer_orders($u->ID);elseif($tab==='addresses')self::addresses($u->ID);elseif($tab==='wishlist')echo do_shortcode('[tager_pro_wishlist]');elseif($tab==='profile')self::profile_form($u);else self::customer_overview($u->ID);?>
        </main></section><?php return ob_get_clean();
    }

    private static function customer_overview($uid){$orders=get_posts(['post_type'=>'tager_order','author'=>$uid,'numberposts'=>-1]);$spent=0;foreach($orders as $o)$spent+=(float)get_post_meta($o->ID,'total',true);echo '<h1>'.esc_html(self::t('مرحبًا بك','Welcome')).'</h1><div class="stat-grid"><div><b>'.count($orders).'</b><span>'.esc_html(self::t('إجمالي الطلبات','Total orders')).'</span></div><div><b>'.self::money($spent).'</b><span>'.esc_html(self::t('إجمالي المشتريات','Total spent')).'</span></div><div><b>'.count((array)get_user_meta($uid,'tager_wishlist',true)).'</b><span>'.esc_html(self::t('المفضلة','Wishlist')).'</span></div></div>';}
    private static function customer_orders($uid){$orders=get_posts(['post_type'=>'tager_order','author'=>$uid,'numberposts'=>-1]);echo '<h2>'.esc_html(self::t('طلباتي','My orders')).'</h2><div class="table-wrap"><table><tr><th>#</th><th>'.esc_html(self::t('التاريخ','Date')).'</th><th>'.esc_html(self::t('الإجمالي','Total')).'</th><th>'.esc_html(self::t('الحالة','Status')).'</th></tr>';foreach($orders as $o)echo '<tr><td>'.$o->ID.'</td><td>'.esc_html(get_the_date('', $o)).'</td><td>'.self::money(get_post_meta($o->ID,'total',true)).'</td><td>'.self::status_badge(get_post_meta($o->ID,'order_status',true)).'</td></tr>';echo '</table></div>';}
    private static function addresses($uid){$a=(array)get_user_meta($uid,'tager_addresses',true);echo '<h2>'.esc_html(self::t('عناويني','My addresses')).'</h2>';foreach($a as $i=>$x)echo '<div class="address-card"><b>'.esc_html($x['label']??'').'</b><p>'.esc_html($x['address']??'').'</p><small>'.esc_html($x['phone']??'').'</small></div>';echo '<form class="form-grid" method="post" action="'.esc_url(admin_url('admin-post.php')).'"><input type="hidden" name="action" value="tager_address_save">'.self::nonce_field('tager_address_save').'<input name="label" placeholder="'.esc_attr(self::t('اسم العنوان: المنزل','Label: Home')).'" required><input name="phone" placeholder="'.esc_attr(self::t('الهاتف','Phone')).'" required><textarea name="address" placeholder="'.esc_attr(self::t('العنوان بالتفصيل','Full address')).'" required></textarea><button class="btn primary">'.esc_html(self::t('إضافة العنوان','Add address')).'</button></form>';}
    private static function profile_form($u){echo '<h2>'.esc_html(self::t('الملف الشخصي','Profile')).'</h2><form class="form-grid" method="post" action="'.esc_url(admin_url('admin-post.php')).'"><input type="hidden" name="action" value="tager_profile_save">'.self::nonce_field('tager_profile_save').'<input name="display_name" value="'.esc_attr($u->display_name).'" required><input name="email" type="email" value="'.esc_attr($u->user_email).'" required><input name="phone" value="'.esc_attr(get_user_meta($u->ID,'phone',true)).'" placeholder="Phone"><input name="password" type="password" placeholder="'.esc_attr(self::t('كلمة مرور جديدة (اختياري)','New password (optional)')).'"><button class="btn primary">'.esc_html(self::t('حفظ','Save')).'</button></form>';}
    public static function profile_save(){if(!is_user_logged_in())wp_die('Login');check_admin_referer('tager_profile_save');$id=get_current_user_id();$data=['ID'=>$id,'display_name'=>sanitize_text_field($_POST['display_name']??''),'user_email'=>sanitize_email($_POST['email']??'')];if(!empty($_POST['password']))$data['user_pass']=$_POST['password'];wp_update_user($data);update_user_meta($id,'phone',sanitize_text_field($_POST['phone']??''));wp_safe_redirect(add_query_arg('tab','profile',self::url('my-account')));exit;}
    public static function address_save(){if(!is_user_logged_in())wp_die('Login');check_admin_referer('tager_address_save');$id=get_current_user_id();$a=(array)get_user_meta($id,'tager_addresses',true);$a[]=['label'=>sanitize_text_field($_POST['label']??''),'phone'=>sanitize_text_field($_POST['phone']??''),'address'=>sanitize_textarea_field($_POST['address']??'')];update_user_meta($id,'tager_addresses',$a);wp_safe_redirect(add_query_arg('tab','addresses',self::url('my-account')));exit;}

    public static function vendor_dashboard(){
        if(!is_user_logged_in())return '<section class="form-wrap"><h1>'.esc_html(self::t('دخول المورد','Vendor sign in')).'</h1>'.wp_login_form(['echo'=>false,'redirect'=>self::url('vendor-dashboard')]).'</section>';
        $u=wp_get_current_user();$vstatus=get_user_meta($u->ID,'vendor_status',true);
        if(in_array('tager_vendor_pending',$u->roles,true)||$vstatus==='pending'||$vstatus==='suspended')return self::vendor_pending_screen($u,$vstatus);
        if(!self::vendor_ok($u->ID))return '<section class="form-wrap"><p>'.esc_html(self::t('هذا الحساب ليس حساب مورد','This is not a vendor account')).'</p></section>';
        $tab=sanitize_key($_GET['tab']??'overview');ob_start(); ?>
        <section class="dash-shell"><aside class="dash-menu"><h3><?php echo esc_html(get_user_meta($u->ID,'store_name',true)?:$u->display_name);?></h3><?php foreach(['overview'=>['الرئيسية','Overview'],'products'=>['المنتجات','Products'],'add-product'=>['إضافة منتج','Add product'],'orders'=>['الطلبات','Orders'],'earnings'=>['الأرباح','Earnings'],'withdrawals'=>['سحب الأرباح','Withdrawals'],'coupons'=>['الكوبونات','Coupons'],'settings'=>['إعدادات المتجر','Store settings']] as $k=>$v)echo '<a class="'.($tab===$k?'active':'').'" href="'.esc_url(add_query_arg('tab',$k,self::url('vendor-dashboard'))).'">'.esc_html(self::t($v[0],$v[1])).'</a>';?><a href="<?php echo esc_url(wp_logout_url(home_url()));?>"><?php echo esc_html(self::t('تسجيل الخروج','Sign out'));?></a></aside><main class="dash-content"><?php
        if($tab==='products')self::vendor_products($u->ID);elseif($tab==='add-product')self::vendor_product_form($u->ID);elseif($tab==='orders')self::vendor_orders($u->ID);elseif($tab==='earnings')self::vendor_earnings($u->ID);elseif($tab==='withdrawals')self::vendor_withdrawals($u->ID);elseif($tab==='coupons')self::vendor_coupons($u->ID);elseif($tab==='settings')self::vendor_settings($u);else self::vendor_overview($u->ID);?></main></section><?php return ob_get_clean();
    }

    private static function vendor_pending_screen($u,$status){$docs=get_user_meta($u->ID,'kyc_status',true);ob_start();?><section class="form-wrap"><h1><?php echo esc_html(self::t('طلب المورد','Vendor application'));?></h1><p><?php echo self::status_badge($status?:'pending');?></p><p><?php echo esc_html(self::t('ارفع المستندات المطلوبة لإتمام المراجعة.','Upload required documents to complete the review.'));?></p><form class="form-grid" method="post" enctype="multipart/form-data" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><input type="hidden" name="action" value="tager_vendor_kyc"><?php echo self::nonce_field('tager_vendor_kyc');?><label><?php echo esc_html(self::t('السجل التجاري','Commercial registration'));?><input type="file" name="commercial_file" accept=".pdf,.jpg,.jpeg,.png"></label><label><?php echo esc_html(self::t('البطاقة الضريبية/الهوية','Tax card / ID'));?><input type="file" name="identity_file" accept=".pdf,.jpg,.jpeg,.png"></label><input name="bank_name" placeholder="<?php echo esc_attr(self::t('اسم البنك','Bank name'));?>"><input name="iban" placeholder="IBAN"><button class="btn primary"><?php echo esc_html(self::t('إرسال للمراجعة','Submit for review'));?></button></form><small><?php echo esc_html($docs?self::t('تم رفع المستندات','Documents uploaded'):self::t('لم تُرفع المستندات بعد','Documents not uploaded yet'));?></small></section><?php return ob_get_clean();}
    public static function vendor_kyc(){if(!is_user_logged_in())wp_die('Login');check_admin_referer('tager_vendor_kyc');$uid=get_current_user_id();require_once ABSPATH.'wp-admin/includes/file.php';require_once ABSPATH.'wp-admin/includes/media.php';require_once ABSPATH.'wp-admin/includes/image.php';foreach(['commercial_file','identity_file'] as $f){if(!empty($_FILES[$f]['name'])){$att=media_handle_upload($f,0);if(!is_wp_error($att))update_user_meta($uid,$f.'_id',$att);}}update_user_meta($uid,'bank_name',sanitize_text_field($_POST['bank_name']??''));update_user_meta($uid,'iban',sanitize_text_field($_POST['iban']??''));update_user_meta($uid,'kyc_status','submitted');wp_safe_redirect(self::url('vendor-dashboard'));exit;}
    private static function vendor_overview($uid){$products=get_posts(['post_type'=>'tager_product','author'=>$uid,'post_status'=>['publish','pending','draft'],'numberposts'=>-1]);$subs=get_posts(['post_type'=>'tager_suborder','author'=>$uid,'numberposts'=>-1]);$sales=0;$pending=0;foreach($subs as $s){$sales+=(float)get_post_meta($s->ID,'vendor_net',true);if(get_post_meta($s->ID,'suborder_status',true)!=='Completed')$pending++;}echo '<h1>'.esc_html(self::t('لوحة المورد','Vendor dashboard')).'</h1><div class="stat-grid"><div><b>'.count($products).'</b><span>'.esc_html(self::t('المنتجات','Products')).'</span></div><div><b>'.count($subs).'</b><span>'.esc_html(self::t('الطلبات','Orders')).'</span></div><div><b>'.self::money($sales).'</b><span>'.esc_html(self::t('صافي الأرباح','Net earnings')).'</span></div><div><b>'.$pending.'</b><span>'.esc_html(self::t('طلبات جارية','Open orders')).'</span></div></div>';}
    private static function vendor_products($uid){$ps=get_posts(['post_type'=>'tager_product','author'=>$uid,'post_status'=>['publish','pending','draft'],'numberposts'=>-1]);echo '<h2>'.esc_html(self::t('منتجاتي','My products')).'</h2><div class="table-wrap"><table><tr><th>'.esc_html(self::t('المنتج','Product')).'</th><th>'.esc_html(self::t('السعر','Price')).'</th><th>'.esc_html(self::t('المخزون','Stock')).'</th><th>'.esc_html(self::t('الحالة','Status')).'</th></tr>';foreach($ps as $p)echo '<tr><td>'.esc_html($p->post_title).'</td><td>'.self::money(get_post_meta($p->ID,'retail_price',true)).'</td><td>'.(int)get_post_meta($p->ID,'stock',true).'</td><td>'.self::status_badge(get_post_meta($p->ID,'approval_status',true)?:$p->post_status).'</td></tr>';echo '</table></div>';}
