    public static function vendor_product_save(){if(!self::vendor_ok())wp_die('Not allowed');check_admin_referer('tager_vendor_product_save');$uid=get_current_user_id();$id=wp_insert_post(['post_type'=>'tager_product','post_status'=>'pending','post_author'=>$uid,'post_title'=>sanitize_text_field($_POST['title_ar']??''),'post_content'=>sanitize_textarea_field($_POST['description_ar']??'')]);$map=['name_en'=>'title_en','description_en'=>'description_en','retail_price'=>'retail','wholesale_price'=>'wholesale','bulk_price'=>'bulk','wholesale_min'=>'wholesale_min','bulk_min'=>'bulk_min','max_qty'=>'max_qty','stock'=>'stock','sku'=>'sku','weight'=>'weight','dimensions'=>'dimensions'];foreach($map as $m=>$f)update_post_meta($id,$m,sanitize_text_field($_POST[$f]??''));update_post_meta($id,'approval_status','pending');if(!empty($_POST['category']))wp_set_object_terms($id,[(int)$_POST['category']],'tager_category');require_once ABSPATH.'wp-admin/includes/file.php';require_once ABSPATH.'wp-admin/includes/media.php';require_once ABSPATH.'wp-admin/includes/image.php';if(!empty($_FILES['product_image']['name'])){$att=media_handle_upload('product_image',$id);if(!is_wp_error($att))set_post_thumbnail($id,$att);}if(!empty($_FILES['gallery']['name'][0])){$ids=[];$files=$_FILES['gallery'];foreach($files['name'] as $i=>$n){if(!$n)continue;$_FILES['tager_gallery_one']=['name'=>$files['name'][$i],'type'=>$files['type'][$i],'tmp_name'=>$files['tmp_name'][$i],'error'=>$files['error'][$i],'size'=>$files['size'][$i]];$att=media_handle_upload('tager_gallery_one',$id);if(!is_wp_error($att))$ids[]=$att;}update_post_meta($id,'gallery_ids',$ids);}wp_safe_redirect(add_query_arg('tab','products',self::url('vendor-dashboard')));exit;}
