    private static function available_balance($uid){$os=get_posts(['post_type'=>'tager_suborder','author'=>$uid,'numberposts'=>-1,'meta_key'=>'suborder_status','meta_value'=>'Completed']);$net=0;foreach($os as $o)$net+=(float)get_post_meta($o->ID,'vendor_net',true);$ws=get_posts(['post_type'=>'tager_withdrawal','author'=>$uid,'numberposts'=>-1,'meta_query'=>[['key'=>'withdrawal_status','value'=>['pending','approved','paid'],'compare'=>'IN']]]);foreach($ws as $w)$net-=(float)get_post_meta($w->ID,'amount',true);return max(0,$net);}
