    public static function vendor_withdrawal(){if(!self::vendor_ok())wp_die('No');check_admin_referer('tager_vendor_withdrawal');$uid=get_current_user_id();$amount=(float)($_POST['amount']??0);$p=self::pro();if($amount<$p['min_withdrawal']||$amount>self::available_balance($uid))wp_die('Invalid amount');$id=wp_insert_post(['post_type'=>'tager_withdrawal','post_status'=>'publish','post_author'=>$uid,'post_title'=>'Withdrawal '.current_time('Ymd-His')]);update_post_meta($id,'amount',$amount);update_post_meta($id,'withdrawal_status','pending');wp_safe_redirect(add_query_arg('tab','withdrawals',self::url('vendor-dashboard')));exit;}
