    public static function cart(){ob_start();?><section class="page-hero"><h1><?php echo esc_html(self::t('سلة المشتريات','Shopping cart'));?></h1></section><div id="tager-cart"></div><form class="checkout-card form-grid" method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>" onsubmit="return tagerPrepareCheckoutPro()"><input type="hidden" name="action" value="tager_pro_checkout"><input type="hidden" name="cart_json" id="cart_json"><?php echo self::nonce_field('tager_pro_checkout');?><input name="customer_name" value="<?php echo esc_attr(is_user_logged_in()?wp_get_current_user()->display_name:'');?>" placeholder="<?php echo esc_attr(self::t('الاسم الكامل','Full name'));?>" required><input name="phone" placeholder="<?php echo esc_attr(self::t('الهاتف','Phone'));?>" required><input type="email" name="email" value="<?php echo esc_attr(is_user_logged_in()?wp_get_current_user()->user_email:'');?>" placeholder="Email" required><textarea name="address" placeholder="<?php echo esc_attr(self::t('عنوان التوصيل','Delivery address'));?>" required></textarea><input name="coupon" placeholder="<?php echo esc_attr(self::t('كود الخصم','Coupon code'));?>"><select name="payment"><option value="cod"><?php echo esc_html(self::t('الدفع عند الاستلام','Cash on delivery'));?></option><option value="bank"><?php echo esc_html(self::t('تحويل بنكي','Bank transfer'));?></option></select><textarea name="notes" placeholder="<?php echo esc_attr(self::t('ملاحظات الطلب','Order notes'));?>"></textarea><label class="check"><input type="checkbox" required> <?php echo esc_html(self::t('أوافق على الشروط وسياسة الإرجاع','I agree to terms and returns policy'));?></label><button class="btn primary"><?php echo esc_html(self::t('تأكيد الطلب','Place order'));?></button></form><script>document.addEventListener('DOMContentLoaded',tagerRenderCart);</script><?php return ob_get_clean();}
    private static function price($id,$qty){$bm=(int)get_post_meta($id,'bulk_min',true);$wm=(int)get_post_meta($id,'wholesale_min',true);if($qty>=$bm)return(float)get_post_meta($id,'bulk_price',true);if($qty>=$wm)return(float)get_post_meta($id,'wholesale_price',true);return(float)get_post_meta($id,'retail_price',true);}
    public static function pro_checkout(){check_admin_referer('tager_pro_checkout');$base=wp_parse_args(get_option('tager_settings',[]),['customer_must_login'=>1,'commission_percent'=>10]);if($base['customer_must_login']&&!is_user_logged_in())wp_die('Login required');$cart=json_decode(stripslashes($_POST['cart_json']??'[]'),true);if(!$cart||!is_array($cart))wp_die('Empty cart');$group=[];$lines=[];$total=0;foreach($cart as $item){$id=(int)($item['id']??0);$qty=max(1,(int)($item['qty']??1));if(get_post_type($id)!=='tager_product'||get_post_status($id)!=='publish')wp_die('Invalid product');$stock=(int)get_post_meta($id,'stock',true);$max=(int)(get_post_meta($id,'max_qty',true)?:9999);if($qty>$stock||$qty>$max)wp_die('Quantity exceeds stock/limits');$price=self::price($id,$qty);$line=$price*$qty;$vendor=(int)get_post_field('post_author',$id);$row=['id'=>$id,'name'=>get_the_title($id),'qty'=>$qty,'unit_price'=>$price,'line_total'=>$line,'vendor_id'=>$vendor];$lines[]=$row;$group[$vendor][]=$row;$total+=$line;update_post_meta($id,'stock',$stock-$qty);} $uid=get_current_user_id();$coupon=strtoupper(sanitize_text_field($_POST['coupon']??''));$discount=0;if($coupon){$cs=get_posts(['post_type'=>'tager_coupon','title'=>$coupon,'post_status'=>'publish','numberposts'=>1]);if($cs){$c=$cs[0];$exp=get_post_meta($c->ID,'expiry',true);if(!$exp||$exp>=current_time('Y-m-d'))$discount=$total*((float)get_post_meta($c->ID,'percent',true)/100);}}$grand=max(0,$total-$discount);$order=wp_insert_post(['post_type'=>'tager_order','post_status'=>'publish','post_author'=>$uid,'post_title'=>'Order '.current_time('Ymd-His')]);foreach(['customer_name','phone','email','address','payment','notes'] as $k)update_post_meta($order,$k,$k==='email'?sanitize_email($_POST[$k]??''):sanitize_textarea_field($_POST[$k]??''));update_post_meta($order,'items',$lines);update_post_meta($order,'subtotal',$total);update_post_meta($order,'discount',$discount);update_post_meta($order,'total',$grand);update_post_meta($order,'order_status','New');update_post_meta($order,'tracking_code','TGR-'.$order.'-'.wp_rand(1000,9999));$rate=(float)$base['commission_percent'];foreach($group as $vendor=>$vlines){$gross=array_sum(array_column($vlines,'line_total'));$comm=$gross*$rate/100;$sub=wp_insert_post(['post_type'=>'tager_suborder','post_status'=>'publish','post_author'=>$vendor,'post_title'=>'Vendor order '.$order.'-'.$vendor]);update_post_meta($sub,'parent_order',$order);update_post_meta($sub,'items',$vlines);update_post_meta($sub,'gross_total',$gross);update_post_meta($sub,'platform_commission',$comm);update_post_meta($sub,'vendor_net',$gross-$comm);update_post_meta($sub,'suborder_status','New');update_post_meta($sub,'customer_name',sanitize_text_field($_POST['customer_name']??''));}wp_safe_redirect(add_query_arg(['msg'=>'order_done','order'=>$order],self::url('my-account')));exit;}

