    public static function admin_menu(){add_submenu_page('tager-control','Vendor Applications','Vendor Applications','manage_options','tager-vendor-applications',[__CLASS__,'admin_vendor_applications']);add_submenu_page('tager-control','Withdrawals','Withdrawals','manage_options','tager-withdrawals',[__CLASS__,'admin_withdrawals']);add_submenu_page('tager-control','Reports','Reports','manage_options','tager-reports',[__CLASS__,'admin_reports']);}
    public static function admin_vendor_applications(){if(!current_user_can('manage_options'))return;$users=get_users(['role__in'=>['tager_vendor_pending','tager_vendor']]);echo '<div class="wrap"><h1>Vendor Applications & KYC</h1><table class="widefat striped"><tr><th>Vendor</th><th>Store</th><th>KYC</th><th>Bank / IBAN</th><th>Documents</th><th>Review</th></tr>';foreach($users as $u){$c=(int)get_user_meta($u->ID,'commercial_file_id',true);$i=(int)get_user_meta($u->ID,'identity_file_id',true);echo '<tr><td>'.esc_html($u->display_name).'<br>'.esc_html($u->user_email).'</td><td>'.esc_html(get_user_meta($u->ID,'store_name',true)).'</td><td>'.esc_html(get_user_meta($u->ID,'kyc_status',true)?:'not submitted').'</td><td>'.esc_html(get_user_meta($u->ID,'bank_name',true)).'<br>'.esc_html(get_user_meta($u->ID,'iban',true)).'</td><td>'.($c?'<a target="_blank" href="'.esc_url(wp_get_attachment_url($c)).'">Commercial</a> ':'').($i?'<a target="_blank" href="'.esc_url(wp_get_attachment_url($i)).'">Identity</a>':'').'</td><td><form method="post" action="'.esc_url(admin_url('admin-post.php')).'"><input type="hidden" name="action" value="tager_admin_vendor_review"><input type="hidden" name="user" value="'.$u->ID.'">'.self::nonce_field('tager_admin_vendor_'.$u->ID).'<select name="decision"><option value="approve">Approve</option><option value="reject">Reject</option><option value="suspend">Suspend</option></select><input name="note" placeholder="Reason / note"><button class="button button-primary">Save</button></form></td></tr>';}echo '</table></div>';}
    public static function admin_vendor_review(){if(!current_user_can('manage_options'))wp_die('No');$uid=(int)($_POST['user']??0);check_admin_referer('tager_admin_vendor_'.$uid);$d=sanitize_key($_POST['decision']??'');$u=new WP_User($uid);if($d==='approve'){$u->set_role('tager_vendor');update_user_meta($uid,'vendor_status','approved');update_user_meta($uid,'kyc_status','approved');}elseif($d==='suspend'){$u->set_role('tager_vendor_pending');update_user_meta($uid,'vendor_status','suspended');}else{$u->set_role('tager_vendor_pending');update_user_meta($uid,'vendor_status','rejected');update_user_meta($uid,'kyc_status','rejected');}update_user_meta($uid,'admin_review_note',sanitize_textarea_field($_POST['note']??''));wp_safe_redirect(admin_url('admin.php?page=tager-vendor-applications'));exit;}
    public static function admin_withdrawals(){$ws=get_posts(['post_type'=>'tager_withdrawal','numberposts'=>-1]);echo '<div class="wrap"><h1>Vendor Withdrawals</h1><table class="widefat striped"><tr><th>#</th><th>Vendor</th><th>Amount</th><th>Status</th><th>Action</th></tr>';foreach($ws as $w)echo '<tr><td>'.$w->ID.'</td><td>'.esc_html(get_the_author_meta('display_name',$w->post_author)).'</td><td>'.self::money(get_post_meta($w->ID,'amount',true)).'</td><td>'.esc_html(get_post_meta($w->ID,'withdrawal_status',true)).'</td><td><form method="post" action="'.esc_url(admin_url('admin-post.php')).'"><input type="hidden" name="action" value="tager_withdrawal_action"><input type="hidden" name="withdrawal" value="'.$w->ID.'">'.self::nonce_field('tager_withdrawal_'.$w->ID).'<select name="status"><option>approved</option><option>paid</option><option>rejected</option></select><button class="button">Update</button></form></td></tr>';echo '</table></div>';}
    public static function withdrawal_action(){if(!current_user_can('manage_options'))wp_die('No');$id=(int)($_POST['withdrawal']??0);check_admin_referer('tager_withdrawal_'.$id);update_post_meta($id,'withdrawal_status',sanitize_key($_POST['status']??'approved'));wp_safe_redirect(admin_url('admin.php?page=tager-withdrawals'));exit;}
    public static function vendor_permission_save(){wp_die('Not implemented');}
    public static function admin_reports(){$orders=get_posts(['post_type'=>'tager_order','numberposts'=>-1]);$sales=0;$discount=0;foreach($orders as $o){$sales+=(float)get_post_meta($o->ID,'total',true);$discount+=(float)get_post_meta($o->ID,'discount',true);} $subs=get_posts(['post_type'=>'tager_suborder','numberposts'=>-1]);$comm=0;foreach($subs as $s)$comm+=(float)get_post_meta($s->ID,'platform_commission',true);echo '<div class="wrap"><h1>Marketplace Reports</h1><div style="display:grid;grid-template-columns:repeat(4,1fr);gap:16px"><div class="postbox" style="padding:20px"><b>Total orders</b><h2>'.count($orders).'</h2></div><div class="postbox" style="padding:20px"><b>Gross sales</b><h2>'.self::money($sales).'</h2></div><div class="postbox" style="padding:20px"><b>Platform commission</b><h2>'.self::money($comm).'</h2></div><div class="postbox" style="padding:20px"><b>Discounts</b><h2>'.self::money($discount).'</h2></div></div></div>';}

    private static function js(){return "
    window.tagerPrepareCheckoutPro=function(){var c=tagerCart();if(!c.length){alert('".esc_js(self::t('السلة فارغة','Cart is empty'))."');return false;}document.getElementById('cart_json').value=JSON.stringify(c);return true;};
    window.tagerWish=function(id){if(!window.tagerWishData){alert('".esc_js(self::t('سجل الدخول أولًا','Please sign in first'))."');return;}var f=new FormData();f.append('action','tager_wishlist_toggle');f.append('product',id);f.append('nonce',tagerWishData.nonce);fetch(tagerWishData.ajax,{method:'POST',body:f}).then(r=>r.json()).then(x=>alert(x.success?'".esc_js(self::t('تم تحديث المفضلة','Wishlist updated'))."':'".esc_js(self::t('تعذر التنفيذ','Unable to update'))."'));};";}
    private static function css(){return "
    .dash-shell{display:grid;grid-template-columns:240px 1fr;gap:24px;margin:24px 0}.dash-menu{background:#103b2a;color:#fff;border-radius:18px;padding:18px;display:flex;flex-direction:column;gap:6px;align-self:start;position:sticky;top:20px}.dash-menu h3{color:#fff;margin:0 0 12px}.dash-menu a{color:#fff;text-decoration:none;padding:11px;border-radius:10px}.dash-menu a:hover,.dash-menu a.active{background:rgba(255,255,255,.15)}.dash-content{min-width:0}.stat-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:14px;margin:18px 0}.stat-grid>div,.balance-card,.address-card{background:#fff;border:1px solid #e5e7eb;border-radius:16px;padding:18px;box-shadow:0 8px 24px rgba(0,0,0,.04)}.stat-grid b,.balance-card b{display:block;font-size:24px;margin-bottom:6px}.market-filters{display:grid;grid-template-columns:2fr 1fr 1fr auto;gap:10px;margin:20px 0}.market-filters input,.market-filters select,.form-grid input,.form-grid select,.form-grid textarea{width:100%;padding:12px;border:1px solid #d7ddd9;border-radius:10px;background:#fff}.form-grid{display:grid;gap:12px}.form-grid.two{grid-template-columns:1fr 1fr}.form-grid textarea{min-height:100px}.tag{display:inline-block;padding:4px 9px;border-radius:999px;font-size:12px}.tag.success{background:#dcfce7;color:#166534}.tag.warning{background:#fef3c7;color:#92400e}.tag.danger{background:#fee2e2;color:#991b1b}.tag.info{background:#dbeafe;color:#1e40af}.wish-btn{position:absolute;top:10px;left:10px;border:0;background:#fff;border-radius:50%;width:36px;height:36px;font-size:22px;cursor:pointer}.product-image{position:relative}.vendor-name{color:#6b7280}.stock-line{font-size:12px;color:#4b5563;margin:8px 0}.checkout-card{max-width:760px;margin:24px auto;background:#fff;border:1px solid #e5e7eb;padding:24px;border-radius:18px}.balance-card{display:flex;justify-content:space-between;align-items:center}.btn.small{padding:7px 10px}.empty-state{grid-column:1/-1;padding:40px;text-align:center;background:#fff;border-radius:16px}.check{display:flex;gap:8px;align-items:center}.check input{width:auto}@media(max-width:850px){.dash-shell{grid-template-columns:1fr}.dash-menu{position:static;display:grid;grid-template-columns:repeat(2,1fr)}.stat-grid{grid-template-columns:repeat(2,1fr)}.market-filters,.form-grid.two{grid-template-columns:1fr}}";}
}
